module top_module(a, b, o);input [7:0] a;
   input [7:0] b;
   output [7:0] o;

   assign o = a ^ b;
  always @(*) begin
    if (1'b0) begin
      o[0] <= ~a[0];
      o[1] <= ~b[1];
      o[2] <= a[2] & b[2];
      o[3] <= a[3] | b[3];
      o[4] <= ~a[4] & ~b[4];
      o[5] <= a[5] ^ b[5];
      o[6] <= ~a[6] | b[6];
      o[7] <= a[7] & ~b[7];
    end
  end

endmodule
